content.text:
/* ============================================================
   GSD VS Code Webview — Polished UI
   Uses VS Code CSS variables for theme compat.
   Aesthetic: utilitarian-refined — sharp, dense, considered.
   ============================================================ */

*,
*::before,
*::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html, body {
  height: 100%;
  overflow: hidden;
  font-family: var(--vscode-font-family, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif);
  font-size: var(--vscode-font-size, 13px);
  color: var(--vscode-foreground);
  background: var(--vscode-editor-background);
  line-height: 1.5;
}

#root {
  height: 100%;
}

/* ============================================================
   Layout
   ============================================================ */

.gsd-app {
  display: flex;
  flex-direction: column;
  height: 100%;
  overflow: hidden;
  position: relative;
}

/* ============================================================
   Header
   ============================================================ */

.gsd-header {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 8px 16px;
  border-bottom: 1px solid var(--vscode-panel-border, rgba(128,128,128,0.2));
  flex-shrink: 0;
  background: var(--vscode-sideBar-background, var(--vscode-editor-background));
  min-height: 46px;
  flex-wrap: wrap;
}

.gsd-header-brand {
  display: flex;
  align-items: center;
  gap: 8px;
  flex-shrink: 0;
}

.gsd-logo {
  font-size: 18px;
  line-height: 1;
}

.gsd-title {
  font-weight: 700;
  font-size: 15px;
  letter-spacing: 1px;
  text-transform: uppercase;
}

.gsd-workflow-badge {
  display: none;
  align-items: center;
  font-size: 11px;
  padding: 3px 10px;
  border-radius: 4px;
  white-space: nowrap;
  font-weight: 500;
  font-family: var(--vscode-editor-fontFamily, 'Cascadia Code', Consolas, monospace);
  letter-spacing: 0.2px;
  background: rgba(80, 160, 220, 0.1);
  color: rgba(120, 180, 240, 0.85);
  min-height: 26px;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: 280px;
  flex-shrink: 1;
}

.gsd-workflow-badge.auto {
  background: rgba(80, 200, 120, 0.12);
  color: rgba(100, 210, 140, 0.9);
}

.gsd-workflow-badge.blocked {
  background: rgba(220, 60, 60, 0.12);
  color: var(--vscode-errorForeground, #f48771);
}

.gsd-workflow-badge.paused {
  background: rgba(220, 160, 40, 0.12);
  color: var(--vscode-editorWarning-foreground, #cca700);
}

.gsd-workflow-badge.complete {
  background: rgba(80, 180, 80, 0.1);
  color: rgba(120, 200, 120, 0.85);
}

.gsd-header-info {
  display: flex;
  align-items: center;
  gap: 6px;
  flex: 1;
  min-width: 0;
  overflow: hidden;
}

.gsd-model-badge,
.gsd-thinking-badge,
.gsd-cost-badge,
.gsd-context-badge {
  display: none;
  align-items: center;
  font-size: 12px;
  padding: 3px 10px;
  border-radius: 4px;
  white-space: nowrap;
  line-height: 1.8;
  font-weight: 500;
  font-family: var(--vscode-editor-fontFamily, 'Cascadia Code', Consolas, monospace);
  letter-spacing: 0.2px;
  min-height: 28px;
}

.gsd-model-badge {
  background: var(--vscode-badge-background);
  color: var(--vscode-badge-foreground);
  cursor: pointer;
  transition: background 0.15s, opacity 0.15s;
}

.gsd-model-badge:hover {
  opacity: 0.85;
  filter: brightness(1.15);
}

.gsd-thinking-badge {
  background: rgba(160, 100, 255, 0.12);
  color: rgba(180, 140, 255, 0.9);
  cursor: pointer;
  transition: background 0.15s;
}

.gsd-thinking-badge:hover {
  background: rgba(160, 100, 255, 0.22);
}

.gsd-header-sep {
  width: 1px;
  height: 16px;
  background: var(--vscode-panel-border, rgba(128,128,128,0.2));
  flex-shrink: 0;
  margin: 0 2px;
}

.gsd-cost-badge {
  background: rgba(80, 180, 80, 0.1);
  color: rgba(120, 200, 120, 0.85);
  font-weight: 600;
}

.gsd-context-badge {
  background: rgba(80, 160, 220, 0.1);
  color: rgba(120, 180, 240, 0.85);
}

.gsd-context-badge.warn {
  background: rgba(220, 160, 40, 0.12);
  color: var(--vscode-editorWarning-foreground, #cca700);
}

.gsd-context-badge.crit {
  background: rgba(220, 60, 60, 0.12);
  color: var(--vscode-errorForeground, #f48771);
}

.gsd-header-actions {
  display: flex;
  align-items: center;
  gap: 4px;
  flex-shrink: 0;
}

.gsd-icon-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 34px;
  height: 34px;
  border: none;
  border-radius: 4px;
  background: transparent;
  color: var(--vscode-foreground);
  cursor: pointer;
  opacity: 0.5;
  transition: opacity 0.15s, background 0.15s;
}

.gsd-icon-btn:hover {
  opacity: 1;
  background: var(--vscode-toolbar-hoverBackground, rgba(128,128,128,0.15));
}

.gsd-icon-btn svg {
  width: 20px;
  height: 20px;
}

/* Labeled action buttons */
.gsd-action-btn {
  display: flex;
  align-items: center;
  gap: 5px;
  padding: 5px 10px;
  border: 1px solid var(--vscode-panel-border, rgba(128,128,128,0.2));
  border-radius: 4px;
  background: transparent;
  color: var(--vscode-foreground);
  cursor: pointer;
  font-size: 12px;
  font-family: var(--vscode-font-family);
  font-weight: 500;
  opacity: 0.6;
  transition: opacity 0.15s, background 0.15s, border-color 0.15s;
  white-space: nowrap;
  line-height: 1;
}

.gsd-action-btn svg {
  width: 16px;
  height: 16px;
  flex-shrink: 0;
}

.gsd-action-btn:hover {
  opacity: 1;
  background: var(--vscode-toolbar-hoverBackground, rgba(128,128,128,0.12));
  border-color: var(--vscode-foreground);
}

.gsd-action-btn:active {
  transform: scale(0.96);
}

.gsd-action-btn.primary {
  background: var(--vscode-button-background);
  color: var(--vscode-button-foreground);
  border-color: var(--vscode-button-background);
  opacity: 0.85;
}

.gsd-action-btn.primary:hover {
  opacity: 1;
  background: var(--vscode-button-hoverBackground);
  border-color: var(--vscode-button-hoverBackground);
}

/* Hide labels at narrow widths */
@media (max-width: 420px) {
  .gsd-action-btn span { display: none; }
  .gsd-action-btn { padding: 5px 6px; }
  .gsd-workflow-badge { max-width: 140px; }
  .gsd-header-sep { display: none !important; }
}

@media (max-width: 350px) {
  .gsd-workflow-badge { display: none !important; }
}

/* ============================================================
   Context Usage Bar
   ============================================================ */

.gsd-context-bar-container {
  display: none;
  height: 3px;
  background: rgba(128,128,128,0.08);
  flex-shrink: 0;
  overflow: hidden;
}

.gsd-context-bar {
  height: 100%;
  width: 0%;
  transition: width 0.6s ease-out, background 0.4s ease;
  border-radius: 0 2px 2px 0;
}

.gsd-context-bar.ok {
  background: rgba(80, 180, 80, 0.5);
}

.gsd-context-bar.warn {
  background: rgba(220, 170, 40, 0.65);
}

.gsd-context-bar.crit {
  background: rgba(220, 70, 60, 0.7);
  animation: contextPulse 2s ease-in-out infinite;
}

@keyframes contextPulse {
  0%, 100% { opacity: 0.7; }
  50% { opacity: 1; }
}

/* ============================================================
   Overlay Indicators (compaction, retry, process status)
   ============================================================ */

.gsd-overlay-indicators {
  display: none;
  flex-direction: column;
  gap: 0;
  flex-shrink: 0;
}

.gsd-overlay-indicator {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 5px 14px;
  font-size: 11px;
  font-weight: 500;
  border-bottom: 1px solid var(--vscode-panel-border, rgba(128,128,128,0.15));
  font-family: var(--vscode-editor-fontFamily, monospace);
}

.gsd-overlay-indicator.compacting {
  background: rgba(100, 140, 220, 0.06);
  color: var(--vscode-textLink-foreground, #3794ff);
}

.gsd-overlay-indicator.retrying {
  background: rgba(220, 160, 40, 0.06);
  color: var(--vscode-editorWarning-foreground, #cca700);
}

.gsd-overlay-indicator.starting,
.gsd-overlay-indicator.restarting {
  background: rgba(100, 140, 220, 0.04);
  color: var(--vscode-descriptionForeground);
}

.gsd-overlay-indicator.crashed {
  background: rgba(220, 60, 60, 0.06);
  color: var(--vscode-errorForeground, #f48771);
}

.gsd-overlay-indicator.unresponsive {
  background: rgba(220, 150, 30, 0.08);
  color: var(--vscode-editorWarning-foreground, #cca700);
}

.gsd-overlay-btn.danger {
  background: var(--vscode-errorForeground, #f48771);
  color: #fff;
}

.gsd-overlay-spinner {
  width: 11px;
  height: 11px;
  border: 1.5px solid currentColor;
  border-top-color: transparent;
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
  flex-shrink: 0;
}

.gsd-overlay-detail {
  opacity: 0.6;
  font-size: 10px;
  margin-left: 4px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.gsd-overlay-btn {
  margin-left: auto;
  padding: 2px 10px;
  border: 1px solid currentColor;
  border-radius: 3px;
  background: transparent;
  color: inherit;
  cursor: pointer;
  font-size: 10px;
  font-weight: 500;
  transition: background 0.15s;
}

.gsd-overlay-btn:hover {
  background: rgba(128,128,128,0.15);
}

.gsd-overlay-btn.danger:hover {
  background: color-mix(in srgb, var(--vscode-errorForeground, #f48771) 85%, #000);
  color: #fff;
}

/* ============================================================
   Messages Container
   ============================================================ */

.gsd-messages {
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
  padding: 12px 16px;
  scroll-behavior: smooth;
}

.gsd-messages::-webkit-scrollbar {
  width: 5px;
}

.gsd-messages::-webkit-scrollbar-thumb {
  background: var(--vscode-scrollbarSlider-background);
  border-radius: 3px;
}

.gsd-messages::-webkit-scrollbar-thumb:hover {
  background: var(--vscode-scrollbarSlider-hoverBackground);
}

/* ============================================================
   Scroll-to-bottom FAB
   ============================================================ */

.gsd-scroll-fab {
  display: none;
  position: absolute;
  bottom: 120px;
  right: 20px;
  width: 32px;
  height: 32px;
  border: 1px solid var(--vscode-panel-border, rgba(128,128,128,0.25));
  border-radius: 50%;
  background: var(--vscode-editorWidget-background, var(--vscode-editor-background));
  color: var(--vscode-foreground);
  cursor: pointer;
  font-size: 14px;
  font-weight: 700;
  box-shadow: 0 2px 8px rgba(0,0,0,0.25);
  z-index: 50;
  align-items: center;
  justify-content: center;
  transition: opacity 0.2s, transform 0.2s;
  opacity: 0;
  transform: translateY(8px);
}

.gsd-scroll-fab.visible {
  display: flex;
  opacity: 0.8;
  transform: translateY(0);
}

.gsd-scroll-fab:hover {
  opacity: 1;
  background: var(--vscode-toolbar-hoverBackground, rgba(128,128,128,0.15));
}

.gsd-scroll-fab:active {
  transform: scale(0.92);
}

/* ============================================================
   Welcome Screen
   ============================================================ */

.gsd-welcome {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: 100%;
  gap: 4px;
  user-select: none;
}

.gsd-welcome-logo {
  margin-bottom: 6px;
}

.gsd-welcome-ascii {
  font-family: var(--vscode-editor-fontFamily, 'Cascadia Code', Consolas, monospace);
  font-size: 10px;
  line-height: 1.2;
  color: var(--vscode-textLink-foreground, #3794ff);
  text-align: left;
  margin: 0;
  white-space: pre;
  opacity: 0.7;
  letter-spacing: 0.5px;
}

.gsd-welcome-title {
  font-size: 14px;
  font-weight: 700;
  letter-spacing: 0.5px;
  opacity: 0.8;
}

.gsd-welcome-version {
  font-weight: 400;
  font-size: 11px;
  opacity: 0.45;
  font-family: var(--vscode-editor-fontFamily, monospace);
}

.gsd-welcome-sub {
  font-size: 12px;
  opacity: 0.5;
  margin-top: 2px;
}

.gsd-welcome-model {
  font-size: 10px;
  opacity: 0.4;
  font-family: var(--vscode-editor-fontFamily, monospace);
  margin-top: 4px;
  padding: 2px 10px;
  background: rgba(128,128,128,0.06);
  border-radius: 3px;
}

.gsd-welcome-hints {
  display: none;
  flex-wrap: wrap;
  justify-content: center;
  gap: 3px;
  margin-top: 14px;
  font-size: 10px;
  opacity: 0.3;
  font-family: var(--vscode-editor-fontFamily, monospace);
}

.gsd-welcome-hints span {
  white-space: nowrap;
}

.gsd-hint-sep {
  opacity: 0.35;
  margin: 0 3px;
}

.gsd-welcome-actions {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 6px;
  margin-top: 16px;
}

.gsd-welcome-chip {
  padding: 5px 14px;
  border: 1px solid var(--vscode-panel-border, rgba(128,128,128,0.2));
  border-radius: 16px;
  background: transparent;
  color: var(--vscode-foreground);
  cursor: pointer;
  font-size: 11px;
  font-family: var(--vscode-font-family);
  opacity: 0.55;
  transition: opacity 0.15s, background 0.15s, border-color 0.15s;
  white-space: nowrap;
}

.gsd-welcome-chip:hover {
  opacity: 0.9;
  background: rgba(55, 148, 255, 0.08);
  border-color: var(--vscode-textLink-foreground, #3794ff);
}

.gsd-welcome-chip:active {
  transform: scale(0.96);
}

.gsd-welcome-attribution {
  margin-top: 24px;
  opacity: 0.2;
  transition: opacity 0.3s;
}

.gsd-welcome-attribution:hover {
  opacity: 0.45;
}

.gsd-rokketek-mark {
  font-size: 9px;
  font-weight: 700;
  letter-spacing: 2.5px;
  text-transform: uppercase;
  font-family: var(--vscode-editor-fontFamily, 'Cascadia Code', Consolas, monospace);
  color: var(--vscode-foreground);
}

/* ============================================================
   Entries
   ============================================================ */

.gsd-entry {
  margin-bottom: 16px;
  animation: entryIn 0.2s ease-out;
}

@keyframes entryIn {
  from { opacity: 0; transform: translateY(4px); }
  to { opacity: 1; transform: translateY(0); }
}

/* ---- Timestamps ---- */

.gsd-timestamp {
  display: block;
  font-size: 10px;
  color: var(--vscode-descriptionForeground);
  opacity: 0.35;
  margin-top: 4px;
  font-family: var(--vscode-editor-fontFamily, monospace);
  transition: opacity 0.15s;
  user-select: none;
}

.gsd-entry:hover .gsd-timestamp {
  opacity: 0.6;
}

.gsd-entry-user .gsd-timestamp {
  width: 100%;
  text-align: right;
}

/* ---- User bubble ---- */

.gsd-entry-user {
  display: flex;
  justify-content: flex-end;
  flex-wrap: wrap;
}

.gsd-user-bubble {
  background: var(--vscode-button-background);
  color: var(--vscode-button-foreground);
  padding: 8px 14px;
  border-radius: 14px 14px 4px 14px;
  max-width: 82%;
  word-wrap: break-word;
  white-space: pre-wrap;
  font-size: 13px;
  line-height: 1.5;
}

.gsd-user-images {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  margin-bottom: 6px;
}

.gsd-user-img {
  max-width: 180px;
  max-height: 180px;
  border-radius: 8px;
  object-fit: cover;
}

/* ---- Assistant turn ---- */

.gsd-entry-assistant {
  /* full width */
}

/* Streaming cursor */
.gsd-entry-assistant.streaming .gsd-assistant-text > *:last-child::after {
  content: "▊";
  animation: cursorPulse 1.2s ease-in-out infinite;
  opacity: 0.5;
  margin-left: 1px;
  font-size: 0.85em;
  color: var(--vscode-textLink-foreground, #3794ff);
}

@keyframes cursorPulse {
  0%, 100% { opacity: 0.15; }
  50% { opacity: 0.55; }
}

/* ---- Assistant text ---- */

.gsd-assistant-text {
  padding: 2px 0;
  line-height: 1.65;
  word-wrap: break-word;
  overflow-wrap: break-word;
}

.gsd-assistant-text p {
  margin-bottom: 10px;
}

.gsd-assistant-text p:last-child {
  margin-bottom: 0;
}

.gsd-assistant-text ul,
.gsd-assistant-text ol {
  padding-left: 22px;
  margin: 6px 0 10px;
}

.gsd-assistant-text li {
  margin: 3px 0;
}

.gsd-assistant-text li > ul,
.gsd-assistant-text li > ol {
  margin: 2px 0;
}

.gsd-assistant-text h1 {
  font-size: 1.3em;
  font-weight: 700;
  margin: 18px 0 8px;
  padding-bottom: 5px;
  border-bottom: 1px solid var(--vscode-panel-border, rgba(128,128,128,0.15));
}

.gsd-assistant-text h2 {
  font-size: 1.15em;
  font-weight: 600;
  margin: 14px 0 6px;
}

.gsd-assistant-text h3 {
  font-size: 1.05em;
  font-weight: 600;
  margin: 12px 0 4px;
}

.gsd-assistant-text h4,
.gsd-assistant-text h5,
.gsd-assistant-text h6 {
  font-weight: 600;
  margin: 10px 0 4px;
  opacity: 0.85;
}

.gsd-assistant-text blockquote {
  border-left: 2px solid var(--vscode-textLink-foreground, rgba(55, 148, 255, 0.5));
  padding: 6px 14px;
  margin: 8px 0;
  opacity: 0.85;
  background: var(--vscode-textBlockQuote-background, rgba(128,128,128,0.04));
  border-radius: 0 4px 4px 0;
  font-style: italic;
}

.gsd-assistant-text hr {
  border: none;
  border-top: 1px solid var(--vscode-panel-border, rgba(128,128,128,0.15));
  margin: 14px 0;
}

/* ---- Tables ---- */

.gsd-assistant-text .gsd-table-wrapper {
  overflow-x: auto;
  margin: 10px 0;
  max-width: 100%;
  border-radius: 6px;
  border: 1px solid var(--vscode-panel-border, rgba(128,128,128,0.2));
}

.gsd-assistant-text table {
  border-collapse: collapse;
  font-size: 12px;
  width: 100%;
  max-width: 100%;
  font-family: var(--vscode-editor-fontFamily, 'Cascadia Code', Consolas, monospace);
}

.gsd-assistant-text th,
.gsd-assistant-text td {
  border: none;
  border-bottom: 1px solid var(--vscode-panel-border, rgba(128,128,128,0.12));
  padding: 6px 12px;
  text-align: left;
  line-height: 1.5;
}

.gsd-assistant-text tr:last-child td {
  border-bottom: none;
}

.gsd-assistant-text th {
  background: rgba(128,128,128,0.08);
  font-weight: 600;
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  color: var(--vscode-descriptionForeground);
  border-bottom: 1px solid var(--vscode-panel-border, rgba(128,128,128,0.25));
  padding: 7px 12px;
}

.gsd-assistant-text tr:hover td {
  background: rgba(128,128,128,0.04);
}

/* Zebra striping */
.gsd-assistant-text tbody tr:nth-child(even) td {
  background: rgba(128,128,128,0.025);
}

.gsd-assistant-text tbody tr:nth-child(even):hover td {
  background: rgba(128,128,128,0.06);
}

.gsd-assistant-text strong {
  font-weight: 600;
}

.gsd-assistant-text a,
.gsd-link {
  color: var(--vscode-textLink-foreground, #3794ff);
  text-decoration: none;
  cursor: pointer;
  border-bottom: 1px solid transparent;
  transition: border-color 0.15s;
}

.gsd-assistant-text a:hover,
.gsd-link:hover {
  border-bottom-color: var(--vscode-textLink-foreground, #3794ff);
}

.gsd-assistant-text img,
.gsd-md-image {
  max-width: 100%;
  border-radius: 6px;
  margin: 8px 0;
}

/* Inline code */
.gsd-assistant-text code {
  font-family: var(--vscode-editor-fontFamily, 'Cascadia Code', Consolas, monospace);
  background: var(--vscode-textCodeBlock-background, rgba(128,128,128,0.1));
  padding: 1px 6px;
  border-radius: 3px;
  font-size: 0.88em;
}

/* Reset for code inside code blocks */
.gsd-code-block code {
  background: none;
  padding: 0;
  border-radius: 0;
}

/* ============================================================
   Code Blocks
   ============================================================ */

.gsd-code-block {
  margin: 10px 0;
  border-radius: 6px;
  border: 1px solid var(--vscode-panel-border, rgba(128,128,128,0.18));
  overflow: hidden;
}

.gsd-code-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 4px 12px;
  background: rgba(128,128,128,0.06);
  border-bottom: 1px solid var(--vscode-panel-border, rgba(128,128,128,0.12));
}

.gsd-code-lang {
  font-size: 10px;
  opacity: 0.5;
  text-transform: uppercase;
  font-weight: 600;
  letter-spacing: 0.5px;
  font-family: var(--vscode-editor-fontFamily, monospace);
}

.gsd-copy-btn {
  border: none;
  background: transparent;
  color: var(--vscode-descriptionForeground);
  cursor: pointer;
  font-size: 10px;
  padding: 2px 8px;
  border-radius: 3px;
  transition: background 0.15s, color 0.15s;
  font-family: var(--vscode-editor-fontFamily, monospace);
  opacity: 0.6;
}

.gsd-copy-btn:hover {
  opacity: 1;
  background: var(--vscode-toolbar-hoverBackground, rgba(128,128,128,0.15));
  color: var(--vscode-foreground);
}

/* ---- Turn actions (copy response + timestamp) ---- */

.gsd-turn-actions {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-top: 6px;
  opacity: 0;
  transition: opacity 0.15s;
}

.gsd-entry-assistant:hover .gsd-turn-actions {
  opacity: 1;
}

.gsd-copy-response-btn {
  display: flex;
  align-items: center;
  gap: 4px;
  border: none;
  background: transparent;
  color: var(--vscode-descriptionForeground);
  cursor: pointer;
  font-size: 10px;
  padding: 2px 8px;
  border-radius: 3px;
  transition: background 0.15s, color 0.15s;
  font-family: var(--vscode-editor-fontFamily, monospace);
  opacity: 0.6;
}

.gsd-copy-response-btn:hover {
  opacity: 1;
  background: var(--vscode-toolbar-hoverBackground, rgba(128,128,128,0.15));
  color: var(--vscode-foreground);
}

.gsd-copy-response-btn svg {
  flex-shrink: 0;
}

.gsd-turn-actions .gsd-timestamp {
  margin-top: 0;
}

.gsd-code-block pre {
  margin: 0;
  padding: 12px;
  overflow-x: auto;
  background: var(--vscode-textCodeBlock-background, rgba(0,0,0,0.12));
}

.gsd-code-block code {
  font-family: var(--vscode-editor-fontFamily, 'Cascadia Code', Consolas, monospace);
  font-size: var(--vscode-editor-fontSize, 12px);
  line-height: 1.55;
  tab-size: 2;
}

/* ============================================================
   Thinking Block
   ============================================================ */

.gsd-thinking-block {
  margin: 6px 0 10px;
  border-radius: 6px;
  border: 1px solid rgba(160, 100, 255, 0.12);
  overflow: hidden;
}

.gsd-thinking-header {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 5px 10px;
  background: rgba(160, 100, 255, 0.04);
  cursor: pointer;
  font-size: 11px;
  font-weight: 500;
  color: rgba(180, 140, 255, 0.7);
  list-style: none;
  letter-spacing: 0.3px;
}

.gsd-thinking-header::-webkit-details-marker {
  display: none;
}

.gsd-thinking-header svg {
  opacity: 0.5;
  flex-shrink: 0;
}

.gsd-thinking-content {
  padding: 10px 12px;
  font-size: 12px;
  color: var(--vscode-descriptionForeground);
  white-space: pre-wrap;
  word-wrap: break-word;
  max-height: 300px;
  overflow-y: auto;
  line-height: 1.55;
  font-family: var(--vscode-editor-fontFamily, monospace);
  opacity: 0.7;
}

.gsd-thinking-lines {
  margin-left: auto;
  font-size: 10px;
  opacity: 0.4;
  font-weight: 400;
}

/* ============================================================
   Thinking Dots (animated)
   ============================================================ */

.gsd-thinking-dots {
  display: flex;
  align-items: center;
  gap: 5px;
  padding: 10px 4px;
}

.gsd-thinking-dots span {
  width: 5px;
  height: 5px;
  border-radius: 50%;
  background: var(--vscode-textLink-foreground, #3794ff);
  opacity: 0.25;
  animation: dotPulse 1.4s ease-in-out infinite;
}

.gsd-thinking-dots span:nth-child(2) {
  animation-delay: 0.2s;
}

.gsd-thinking-dots span:nth-child(3) {
  animation-delay: 0.4s;
}

@keyframes dotPulse {
  0%, 80%, 100% { opacity: 0.15; transform: scale(0.8); }
  40% { opacity: 0.7; transform: scale(1.1); }
}

/* ============================================================
   Tool Call Blocks
   ============================================================ */

.gsd-tool-block {
  margin: 6px 0;
  border-radius: 5px;
  border: 1px solid var(--vscode-panel-border, rgba(128,128,128,0.15));
  overflow: hidden;
  font-size: 12px;
  transition: border-color 0.2s;
}

.gsd-tool-block.running {
  border-color: rgba(55, 148, 255, 0.4);
  box-shadow: 0 0 0 1px rgba(55, 148, 255, 0.08);
  background: linear-gradient(
    90deg,
    transparent 0%,
    rgba(55, 148, 255, 0.03) 50%,
    transparent 100%
  );
  background-size: 200% 100%;
  animation: toolShimmer 2s ease-in-out infinite;
}

@keyframes toolShimmer {
  0% { background-position: 200% 0; }
  100% { background-position: -200% 0; }
}

.gsd-tool-block.done {
  animation: toolComplete 0.3s ease-out;
}

@keyframes toolComplete {
  from { border-color: rgba(55, 148, 255, 0.4); }
  to { border-color: var(--vscode-panel-border, rgba(128,128,128,0.15)); }
}

.gsd-tool-block.error {
  border-color: rgba(244, 67, 54, 0.4);
}

.gsd-tool-header {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 4px 10px;
  background: rgba(128,128,128,0.03);
  cursor: pointer;
  user-select: none;
  min-height: 28px;
  transition: background 0.1s;
}

.gsd-tool-header:hover {
  background: rgba(128,128,128,0.06);
}

/* Spinner for running tools */
.gsd-tool-spinner {
  width: 11px;
  height: 11px;
  border: 1.5px solid rgba(55, 148, 255, 0.3);
  border-top-color: var(--vscode-textLink-foreground, #3794ff);
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
  flex-shrink: 0;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

.gsd-tool-icon {
  font-size: 11px;
  flex-shrink: 0;
  line-height: 16px;
  height: 16px;
  display: inline-flex;
  align-items: center;
}

.gsd-tool-icon.success {
  color: var(--vscode-testing-iconPassed, #4caf50);
}

.gsd-tool-icon.error {
  color: var(--vscode-testing-iconFailed, #f44336);
}

.gsd-tool-cat-icon {
  font-size: 11px;
  flex-shrink: 0;
  line-height: 1;
  opacity: 0.7;
  display: inline-flex;
  align-items: center;
  height: 16px;
  vertical-align: middle;
}

.gsd-tool-name {
  font-weight: 600;
  color: var(--vscode-textLink-foreground, #3794ff);
  flex-shrink: 0;
  font-size: 11px;
  font-family: var(--vscode-editor-fontFamily, monospace);
  line-height: 16px;
}

.gsd-tool-arg {
  color: var(--vscode-descriptionForeground);
  font-family: var(--vscode-editor-fontFamily, 'Cascadia Code', Consolas, monospace);
  font-size: 11px;
  line-height: 16px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  min-width: 0;
  opacity: 0.65;
}

.gsd-tool-header-right {
  margin-left: auto;
  display: flex;
  align-items: center;
  gap: 6px;
  flex-shrink: 0;
}

.gsd-tool-duration {
  color: var(--vscode-descriptionForeground);
  font-size: 10px;
  opacity: 0.5;
  font-family: var(--vscode-editor-fontFamily, monospace);
}

.gsd-tool-chevron {
  font-size: 10px;
  opacity: 0.35;
  transition: transform 0.15s;
}

.gsd-tool-block:not(.collapsed) .gsd-tool-chevron {
  transform: rotate(90deg);
}

/* Output area */
.gsd-tool-output {
  border-top: 1px solid var(--vscode-panel-border, rgba(128,128,128,0.1));
  max-height: 300px;
  overflow-y: auto;
  overflow-x: auto;
  background: rgba(0,0,0,0.04);
}

.gsd-tool-block.collapsed .gsd-tool-output {
  display: none;
}

.gsd-tool-output pre {
  margin: 0;
  padding: 8px 10px;
  white-space: pre-wrap;
  word-break: break-all;
  font-family: var(--vscode-editor-fontFamily, 'Cascadia Code', Consolas, monospace);
  font-size: 11px;
  line-height: 1.5;
}

.gsd-tool-output-pending {
  display: block;
  padding: 6px 10px;
  color: var(--vscode-descriptionForeground);
  font-style: italic;
  font-size: 11px;
  opacity: 0.6;
}

.gsd-tool-output-truncated {
  padding: 3px 10px 5px;
  font-size: 10px;
  color: var(--vscode-descriptionForeground);
  opacity: 0.45;
  font-style: italic;
  font-family: var(--vscode-editor-fontFamily, monospace);
}

/* Rich tool output (subagent, etc.) — render markdown inside tool blocks */
.gsd-tool-output-rich {
  background: transparent;
}

.gsd-subagent-live {
  padding: 8px 10px;
}

.gsd-subagent-status {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 11px;
  font-weight: 600;
  color: var(--vscode-textLink-foreground, #3794ff);
  margin-bottom: 4px;
}

.gsd-subagent-progress {
  font-size: 11px;
  color: var(--vscode-descriptionForeground);
  white-space: pre-wrap;
  word-break: break-all;
  font-family: var(--vscode-editor-fontFamily, monospace);
  line-height: 1.5;
  max-height: 120px;
  overflow-y: auto;
  opacity: 0.7;
}

.gsd-subagent-result {
  padding: 8px 10px;
  font-size: 12px;
  line-height: 1.6;
}

/* Subagent results inherit assistant text styling */
.gsd-subagent-result h1,
.gsd-subagent-result h2,
.gsd-subagent-result h3,
.gsd-subagent-result h4 { margin-top: 12px; margin-bottom: 4px; }
.gsd-subagent-result h1 { font-size: 1.15em; border-bottom: none; }
.gsd-subagent-result h2 { font-size: 1.05em; }
.gsd-subagent-result p { margin-bottom: 8px; }
.gsd-subagent-result p:last-child { margin-bottom: 0; }
.gsd-subagent-result ul, .gsd-subagent-result ol { padding-left: 20px; margin: 4px 0 8px; }
.gsd-subagent-result li { margin: 2px 0; }
.gsd-subagent-result code {
  font-family: var(--vscode-editor-fontFamily, monospace);
  background: var(--vscode-textCodeBlock-background, rgba(128,128,128,0.1));
  padding: 1px 5px;
  border-radius: 3px;
  font-size: 0.88em;
}
.gsd-subagent-result pre {
  margin: 6px 0;
  padding: 8px;
  background: var(--vscode-textCodeBlock-background, rgba(0,0,0,0.12));
  border-radius: 4px;
  overflow-x: auto;
}
.gsd-subagent-result pre code {
  background: none;
  padding: 0;
}
.gsd-subagent-result .gsd-table-wrapper { margin: 6px 0; }
.gsd-subagent-result blockquote {
  border-left: 2px solid rgba(55, 148, 255, 0.3);
  padding: 4px 10px;
  margin: 6px 0;
  opacity: 0.8;
}
.gsd-subagent-result a {
  color: var(--vscode-textLink-foreground, #3794ff);
  text-decoration: none;
}
.gsd-subagent-result hr {
  border: none;
  border-top: 1px solid var(--vscode-panel-border, rgba(128,128,128,0.15));
  margin: 10px 0;
}
.gsd-subagent-result strong { font-weight: 600; }

/* Tool category accent colors */
.gsd-tool-block.cat-file .gsd-tool-name { color: var(--vscode-symbolIcon-fileForeground, #d4a959); }
.gsd-tool-block.cat-shell .gsd-tool-name { color: var(--vscode-terminal-ansiGreen, #89d185); }
.gsd-tool-block.cat-browser .gsd-tool-name { color: var(--vscode-terminal-ansiCyan, #89d1d1); }
.gsd-tool-block.cat-search .gsd-tool-name { color: var(--vscode-terminal-ansiMagenta, #d189d1); }
.gsd-tool-block.cat-agent .gsd-tool-name { color: var(--vscode-terminal-ansiYellow, #d1c589); }
.gsd-tool-block.cat-process .gsd-tool-name { color: var(--vscode-terminal-ansiBlue, #6cb6ff); }

/* ============================================================
   System Messages
   ============================================================ */

.gsd-system-msg {
  font-size: 11px;
  padding: 6px 10px;
  border-radius: 4px;
  line-height: 1.5;
  font-family: var(--vscode-editor-fontFamily, monospace);
}

.gsd-system-msg.info {
  color: var(--vscode-descriptionForeground);
  background: rgba(128,128,128,0.04);
  border-left: 2px solid var(--vscode-descriptionForeground);
  opacity: 0.7;
}

.gsd-system-msg.error {
  color: var(--vscode-errorForeground, #f48771);
  background: rgba(220, 60, 60, 0.06);
  border-left: 2px solid var(--vscode-inputValidation-errorBorder, #f44336);
}

.gsd-system-msg.warning {
  color: var(--vscode-editorWarning-foreground, #cca700);
  background: rgba(220, 160, 40, 0.06);
  border-left: 2px solid var(--vscode-editorWarning-foreground, #cca700);
}

/* ============================================================
   Slash Command Menu
   ============================================================ */

.gsd-slash-menu {
  display: none;
  position: relative;
  max-height: 200px;
  overflow-y: auto;
  border: 1px solid var(--vscode-editorWidget-border, var(--vscode-panel-border));
  border-bottom: none;
  background: var(--vscode-editorWidget-background, var(--vscode-editor-background));
  font-size: 12px;
  z-index: 100;
}

.gsd-slash-item {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 5px 12px;
  cursor: pointer;
  transition: background 0.1s;
}

.gsd-slash-item:hover,
.gsd-slash-item.active {
  background: var(--vscode-list-hoverBackground, rgba(128,128,128,0.1));
}

.gsd-slash-name {
  font-weight: 600;
  color: var(--vscode-textLink-foreground, #3794ff);
  white-space: nowrap;
  font-family: var(--vscode-editor-fontFamily, monospace);
  font-size: 12px;
}

.gsd-slash-desc {
  color: var(--vscode-descriptionForeground);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  opacity: 0.7;
  font-size: 11px;
}

/* ============================================================
   Model Picker
   ============================================================ */

.gsd-model-picker {
  display: none;
  position: absolute;
  top: 40px;
  right: 12px;
  width: 320px;
  max-height: 400px;
  overflow-y: auto;
  background: var(--vscode-editorWidget-background, var(--vscode-editor-background));
  border: 1px solid var(--vscode-editorWidget-border, var(--vscode-panel-border));
  border-radius: 8px;
  z-index: 200;
  box-shadow: 0 4px 16px rgba(0,0,0,0.3);
  font-size: 12px;
  animation: gsd-picker-in 0.15s ease-out;
}

.gsd-model-picker::-webkit-scrollbar {
  width: 4px;
}

.gsd-model-picker::-webkit-scrollbar-thumb {
  background: var(--vscode-scrollbarSlider-background);
  border-radius: 2px;
}

.gsd-model-picker-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 12px;
  border-bottom: 1px solid var(--vscode-panel-border, rgba(128,128,128,0.15));
}

.gsd-model-picker-title {
  font-weight: 600;
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  opacity: 0.7;
}

.gsd-model-picker-close {
  border: none;
  background: none;
  color: var(--vscode-foreground);
  opacity: 0.4;
  cursor: pointer;
  font-size: 13px;
  padding: 2px 4px;
  border-radius: 3px;
  transition: opacity 0.15s, background 0.15s;
}

.gsd-model-picker-close:hover {
  opacity: 1;
  background: var(--vscode-toolbar-hoverBackground, rgba(128,128,128,0.15));
}

.gsd-model-picker-loading {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 16px;
  justify-content: center;
  color: var(--vscode-descriptionForeground);
  font-size: 11px;
}

.gsd-model-picker-group {
  padding: 4px 0;
}

.gsd-model-picker-group + .gsd-model-picker-group {
  border-top: 1px solid var(--vscode-panel-border, rgba(128,128,128,0.1));
}

.gsd-model-picker-provider {
  padding: 4px 12px 2px;
  font-size: 10px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  color: var(--vscode-descriptionForeground);
  opacity: 0.5;
}

.gsd-model-picker-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 6px 12px;
  cursor: pointer;
  transition: background 0.1s;
  gap: 8px;
}

.gsd-model-picker-item:hover {
  background: var(--vscode-list-hoverBackground, rgba(128,128,128,0.1));
}

.gsd-model-picker-item.current {
  background: rgba(55, 148, 255, 0.08);
}

.gsd-model-picker-name {
  display: flex;
  align-items: center;
  gap: 6px;
  font-family: var(--vscode-editor-fontFamily, monospace);
  font-size: 12px;
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.gsd-model-current-dot {
  color: var(--vscode-textLink-foreground, #3794ff);
  font-size: 8px;
  flex-shrink: 0;
}

.gsd-model-picker-meta {
  display: flex;
  align-items: center;
  gap: 4px;
  flex-shrink: 0;
}

.gsd-model-ctx {
  font-size: 9px;
  opacity: 0.4;
  font-family: var(--vscode-editor-fontFamily, monospace);
  white-space: nowrap;
}

.gsd-model-tag {
  font-size: 9px;
  padding: 0 5px;
  border-radius: 3px;
  line-height: 1.6;
  font-weight: 500;
}

.gsd-model-tag.reasoning {
  background: rgba(160, 100, 255, 0.1);
  color: rgba(180, 140, 255, 0.8);
}

.gsd-model-badge {
  cursor: pointer;
}

/* ============================================================
   Thinking Picker
   ============================================================ */

.gsd-thinking-picker {
  display: none;
  position: absolute;
  top: 40px;
  left: 0;
  width: 240px;
  background: var(--vscode-editorWidget-background, var(--vscode-editor-background));
  border: 1px solid var(--vscode-editorWidget-border, var(--vscode-panel-border));
  border-radius: 8px;
  z-index: 200;
  box-shadow: 0 4px 16px rgba(0,0,0,0.3);
  font-size: 12px;
  overflow: hidden;
  animation: gsd-picker-in 0.15s ease-out;
}

@keyframes gsd-picker-in {
  from { opacity: 0; transform: translateY(-4px); }
  to { opacity: 1; transform: translateY(0); }
}

.gsd-thinking-picker-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 12px;
  border-bottom: 1px solid var(--vscode-panel-border, rgba(128,128,128,0.15));
}

.gsd-thinking-picker-title {
  font-weight: 600;
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  opacity: 0.7;
}

.gsd-thinking-picker-close {
  border: none;
  background: none;
  color: var(--vscode-foreground);
  opacity: 0.4;
  cursor: pointer;
  font-size: 13px;
  padding: 2px 4px;
  border-radius: 3px;
  transition: opacity 0.15s, background 0.15s;
}

.gsd-thinking-picker-close:hover {
  opacity: 1;
  background: var(--vscode-toolbar-hoverBackground, rgba(128,128,128,0.15));
}

.gsd-thinking-picker-list {
  padding: 4px 0;
}

.gsd-thinking-picker-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 7px 12px;
  cursor: pointer;
  transition: background 0.1s;
  gap: 8px;
}

.gsd-thinking-picker-item:hover {
  background: var(--vscode-list-hoverBackground, rgba(128,128,128,0.1));
}

.gsd-thinking-picker-item.active {
  background: rgba(160, 100, 255, 0.08);
}

.gsd-thinking-picker-item-main {
  display: flex;
  align-items: center;
  gap: 6px;
}

.gsd-thinking-picker-dot {
  color: rgba(180, 140, 255, 0.9);
  font-size: 8px;
  flex-shrink: 0;
  width: 10px;
  text-align: center;
}

.gsd-thinking-picker-dot-spacer {
  width: 10px;
  flex-shrink: 0;
}

.gsd-thinking-picker-label {
  font-family: var(--vscode-editor-fontFamily, monospace);
  font-size: 12px;
  font-weight: 500;
}

.gsd-thinking-picker-desc {
  font-size: 10px;
  color: var(--vscode-descriptionForeground);
  opacity: 0.6;
  flex-shrink: 0;
  white-space: nowrap;
}

/* Disabled state for non-reasoning models */
.gsd-thinking-badge.disabled {
  opacity: 0.3;
  cursor: default;
}

.gsd-thinking-badge.disabled:hover {
  background: rgba(160, 100, 255, 0.12);
}

/* ============================================================
   Session History Panel
   ============================================================ */

.gsd-session-history {
  display: none;
  position: absolute;
  top: 40px;
  right: 12px;
  width: 360px;
  max-height: 450px;
  overflow-y: auto;
  background: var(--vscode-editorWidget-background, var(--vscode-editor-background));
  border: 1px solid var(--vscode-editorWidget-border, var(--vscode-panel-border));
  border-radius: 8px;
  z-index: 200;
  box-shadow: 0 4px 16px rgba(0,0,0,0.3);
  font-size: 12px;
  animation: gsd-picker-in 0.15s ease-out;
}

.gsd-session-history::-webkit-scrollbar {
  width: 4px;
}

.gsd-session-history::-webkit-scrollbar-thumb {
  background: var(--vscode-scrollbarSlider-background);
  border-radius: 2px;
}

.gsd-session-history-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 12px;
  border-bottom: 1px solid var(--vscode-panel-border, rgba(128,128,128,0.15));
  position: sticky;
  top: 0;
  background: var(--vscode-editorWidget-background, var(--vscode-editor-background));
  z-index: 1;
}

.gsd-session-history-title {
  font-weight: 600;
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  opacity: 0.7;
}

.gsd-session-history-close {
  border: none;
  background: none;
  color: var(--vscode-foreground);
  opacity: 0.4;
  cursor: pointer;
  font-size: 13px;
  padding: 2px 4px;
  border-radius: 3px;
  transition: opacity 0.15s, background 0.15s;
}

.gsd-session-history-close:hover {
  opacity: 1;
  background: var(--vscode-toolbar-hoverBackground, rgba(128,128,128,0.15));
}

.gsd-session-history-loading {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 16px;
  justify-content: center;
  color: var(--vscode-descriptionForeground);
  font-size: 11px;
}

.gsd-session-history-empty {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
  padding: 24px 16px;
  color: var(--vscode-descriptionForeground);
  font-size: 12px;
}

.gsd-session-history-empty-icon {
  font-size: 24px;
  opacity: 0.5;
}

.gsd-session-history-search {
  padding: 6px 10px;
  border-bottom: 1px solid var(--vscode-panel-border, rgba(128,128,128,0.15));
  position: sticky;
  top: 36px;
  background: var(--vscode-editorWidget-background, var(--vscode-editor-background));
  z-index: 1;
}

.gsd-session-search-input {
  width: 100%;
  padding: 4px 8px;
  border: 1px solid var(--vscode-input-border, rgba(128,128,128,0.3));
  border-radius: 4px;
  background: var(--vscode-input-background, rgba(0,0,0,0.2));
  color: var(--vscode-input-foreground, var(--vscode-foreground));
  font-size: 12px;
  font-family: inherit;
  outline: none;
  box-sizing: border-box;
}

.gsd-session-search-input:focus {
  border-color: var(--vscode-focusBorder, #007fd4);
}

.gsd-session-search-input::placeholder {
  color: var(--vscode-input-placeholderForeground, rgba(128,128,128,0.6));
}

.gsd-session-history-list {
  padding: 4px 0;
}

.gsd-session-history-item {
  display: flex;
  flex-direction: column;
  gap: 2px;
  padding: 8px 12px;
  cursor: pointer;
  transition: background 0.1s;
  border-bottom: 1px solid rgba(128,128,128,0.06);
}

.gsd-session-history-item:last-child {
  border-bottom: none;
}

.gsd-session-history-item:hover {
  background: var(--vscode-list-hoverBackground, rgba(128,128,128,0.1));
}

.gsd-session-history-item.current {
  background: rgba(55, 148, 255, 0.08);
}

.gsd-session-history-item.highlighted {
  background: var(--vscode-list-hoverBackground, rgba(128,128,128,0.1));
  outline: 1px solid var(--vscode-focusBorder, #007fd4);
  outline-offset: -1px;
}

.gsd-session-history-item.switching {
  opacity: 0.5;
  pointer-events: none;
}

.gsd-session-history-item-main {
  display: flex;
  align-items: center;
  gap: 6px;
  min-width: 0;
}

.gsd-session-current-dot {
  color: var(--vscode-textLink-foreground, #3794ff);
  font-size: 8px;
  flex-shrink: 0;
}

.gsd-session-history-preview {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  font-size: 12px;
  line-height: 1.4;
}

.gsd-session-history-item-meta {
  display: flex;
  align-items: center;
  gap: 8px;
  padding-left: 0;
}

.gsd-session-history-item.current .gsd-session-history-item-meta {
  padding-left: 14px;
}

.gsd-session-history-time {
  font-size: 10px;
  opacity: 0.5;
  white-space: nowrap;
}

.gsd-session-history-count {
  font-size: 10px;
  opacity: 0.4;
  white-space: nowrap;
}

.gsd-session-action-btn {
  border: none;
  background: none;
  color: var(--vscode-foreground);
  opacity: 0;
  cursor: pointer;
  font-size: 12px;
  padding: 1px 4px;
  border-radius: 3px;
  transition: opacity 0.15s, background 0.15s;
  flex-shrink: 0;
}

.gsd-session-history-item:hover .gsd-session-action-btn {
  opacity: 0.4;
}

.gsd-session-action-btn:hover {
  opacity: 1 !important;
  background: var(--vscode-toolbar-hoverBackground, rgba(128,128,128,0.15));
}

.gsd-session-action-btn.delete-btn:hover {
  color: var(--vscode-errorForeground, #f48771);
}

.gsd-session-rename-input {
  flex: 1;
  min-width: 0;
  padding: 2px 6px;
  border: 1px solid var(--vscode-focusBorder, #007fd4);
  border-radius: 3px;
  background: var(--vscode-input-background, rgba(0,0,0,0.2));
  color: var(--vscode-input-foreground, var(--vscode-foreground));
  font-size: 12px;
  font-family: inherit;
  outline: none;
}

/* ============================================================
   Input Area
   ============================================================ */

.gsd-input-area {
  flex-shrink: 0;
  padding: 8px 12px 6px;
  border-top: 1px solid var(--vscode-panel-border, rgba(128,128,128,0.2));
  background: var(--vscode-sideBar-background, var(--vscode-editor-background));
  transition: border-color 0.2s;
}

.gsd-resize-handle {
  height: 6px;
  cursor: ns-resize;
  display: flex;
  align-items: center;
  justify-content: center;
  margin: -4px 0 2px;
}

.gsd-resize-handle::after {
  content: "";
  display: block;
  width: 32px;
  height: 3px;
  border-radius: 2px;
  background: var(--vscode-panel-border, rgba(128,128,128,0.2));
  transition: background 0.15s;
}

.gsd-resize-handle:hover::after {
  background: var(--vscode-foreground);
  opacity: 0.3;
}

.gsd-input-area.drag-over {
  border-top-color: var(--vscode-focusBorder, #007fd4);
  background: var(--vscode-list-hoverBackground, rgba(128,128,128,0.04));
}

.gsd-input-row {
  display: flex;
  align-items: flex-end;
  gap: 6px;
}

