  background: var(--vscode-sideBar-background, var(--vscode-editor-background));
  transition: border-color 0.2s;
}

.gsd-resize-handle {
  height: 6px;
  cursor: ns-resize;
  display: flex;
  align-items: center;
  justify-content: center;
  margin: -4px 0 2px;
}

.gsd-resize-handle::after {
  content: "";
  display: block;
  width: 32px;
  height: 3px;
  border-radius: 2px;
  background: var(--vscode-panel-border, rgba(128,128,128,0.2));
  transition: background 0.15s;
}

.gsd-resize-handle:hover::after {
  background: var(--vscode-foreground);
  opacity: 0.3;
}

.gsd-input-area.drag-over {
  border-top-color: var(--vscode-focusBorder, #007fd4);
  background: var(--vscode-list-hoverBackground, rgba(128,128,128,0.04));
}

.gsd-input-row {
  display: flex;
  align-items: flex-end;
  gap: 6px;
}

content.text:
.gsd-input-wrapper {
