/* ============================================================
   Image Preview
   ============================================================ */

.gsd-image-preview {
  display: none;
  flex-wrap: wrap;
  gap: 6px;
  padding-bottom: 6px;
}

.gsd-image-thumb {
  position: relative;
  width: 56px;
  height: 56px;
  border-radius: 6px;
  overflow: hidden;
  border: 1px solid var(--vscode-panel-border, rgba(128,128,128,0.2));
}

.gsd-image-thumb img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.gsd-image-remove {
  position: absolute;
  top: 2px;
  right: 2px;
  width: 16px;
  height: 16px;
  border: none;
  border-radius: 50%;
  background: rgba(0,0,0,0.7);
  color: #fff;
  font-size: 11px;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  line-height: 1;
  opacity: 0;
  transition: opacity 0.15s;
}

.gsd-image-thumb:hover .gsd-image-remove {
  opacity: 1;
}

