.gsd-ui-resolved.accepted .gsd-ui-resolved-icon {
  color: var(--vscode-testing-iconPassed, #4caf50);
}

.gsd-ui-resolved.cancelled .gsd-ui-resolved-icon {
  color: var(--vscode-descriptionForeground);
